// src/components/AITools.jsx
import './AITools.css';

const tools = [
  { icon: '🤖', name: 'ChatGPT', vendor: 'OpenAI', desc: 'OpenAI\'s flagship model for brainstorming, architecture design, debugging, and generating entire code modules from natural language.' },
  { icon: '🐙', name: 'GitHub Copilot', vendor: 'GitHub × OpenAI', desc: 'Your AI pair programmer inside your editor. Context-aware code completions, function generation, and test writing as you type.' },
  { icon: '🔁', name: 'Replit AI', vendor: 'Replit', desc: 'Build, run, and deploy full-stack apps directly in the browser. Replit AI helps scaffold projects and fix bugs on the fly.' },
  { icon: '⌨️', name: 'Cursor AI', vendor: 'Cursor', desc: 'The AI-first code editor that lets you chat with your codebase. Refactor, explain, and generate with full project context.' },
  { icon: '♊', name: 'Google Gemini', vendor: 'Google DeepMind', desc: 'Google\'s multimodal AI powerhouse. Ideal for reasoning through complex problems, analyzing visuals, and API integrations.' },
  { icon: '🐙', name: 'GitHub Copilot', vendor: 'GitHub × OpenAI', desc: 'Your AI pair programmer inside your editor. Context-aware code completions, function generation, and test writing as you type.' },
  { icon: '🧠', name: 'Claude AI', vendor: 'Anthropic', desc: 'Excels at nuanced coding, detailed explanations, and writing clean, well-documented production-grade code at speed.' },
];

export default function AITools() {
  return (
    <section id="tools" className="tools-section">
      <p className="section-tag">Arsenal</p>
      <h2 className="section-title">
        AI Tools <span className="gradient-text">Allowed</span>
      </h2>
      <p className="section-desc">
        You're not building alone. These AI-powered tools are your co-pilots for the hackathon.
        Each brings unique superpowers to your development workflow.
      </p>

      <div className="tools-grid fade-in">
        {tools.map(({ icon, name, vendor, desc }) => (
          <div className="tool-card card" key={name}>
            <div className="tool-logo">{icon}</div>
            <h4>{name}</h4>
            <p>{desc}</p>
            <span className="tool-tag">{vendor}</span>
          </div>
        ))}
      </div>
    </section>
  );
}
